#!/usr/bin/env python3 """parser.core — Python source code → graph-ai.json IR (MVP subset).  Supports:   - control:   if / elif / else / for / while / break / continue / return   - structure: function_def / class_def   - action:    assign / augassign / call / import / import_from   - data:      literal / name / attribute / binop / unaryop / compare / subscr / list_literal / tuple_literal / dict_literal   - escape:    CodeBlockNode (fallback for unsupported constructs)  设计原则:   - 失败降级为 CodeBlockNode，不崩溃   - 保留 sourceMap 行号映射   - 函数参数保留真实名称（PortDef.name = 参数名）   - if/elif/else 链通过 elif_marker 标记，codegen 可还原 elif """  import ast from pathlib import Path from typing import Any  from packages.graph_ir import (     Graph, Node, Edge, PortDef, Scope,     NODE_TYPES, CATEGORY_ESCAPE, CATEGORY_CONTROL, CATEGORY_STRUCTURE,     CATEGORY_ACTION, CATEGORY_DATA,     generate_id, build_ir, )  _OP_MAP = {     ast.Add: "Add", ast.Sub: "Sub", ast.Mult: "Mult", ast.Div: "Div",     ast.FloorDiv: "FloorDiv", ast.Mod: "Mod", ast.Pow: "Pow",     ast.LShift: "LShift", ast.RShift: "RShift",     ast.BitOr: "BitOr", ast.BitXor: "BitXor", ast.BitAnd: "BitAnd", } _UNARY_MAP = {     ast.UAdd: "UAdd", ast.USub: "USub", ast.Not: "Not", ast.Invert: "Invert", } _CMP_MAP = {     ast.Eq: "Eq", ast.NotEq: "NotEq", ast.Lt: "Lt", ast.LtE: "LtE",     ast.Gt: "Gt", ast.GtE: "GtE", ast.Is: "Is", ast.IsNot: "IsNot",     ast.In: "In", ast.NotIn: "NotIn", }   def _make_code_block(node_id: str, code: str) -> Node:     return Node(         id=node_id, category=CATEGORY_ESCAPE, type="CodeBlockNode",         label="Code Block (fallback)", codeBlock=code,         inputs=[], outputs=[PortDef("out")],     )   class PythonParser:     """Convert Python ast.Module → Graph IR.      Usage:         parser = PythonParser(source, filename)         ir = parser.parse()   # → dict (graph-ai.json structure)     """      def __init__(self, source: str, filename: str = "<unknown>"):         self.source = source         self.filename = filename         self.graph: Graph = Graph()         self.source_map: dict[str, dict] = {}         self._counter = 0         self._last_stmt_id: str | None = None      # ── ID generation ──────────────────────────────────────────────────────      def _new_id(self, prefix: str = "n") -> str:         self._counter += 1         return f"node_{prefix}_{self._counter}"      def _record_source(self, node_id: str, ast_node: ast.AST) -> None:         if hasattr(ast_node, "lineno"):             self.source_map[node_id] = {                 "lineStart": ast_node.lineno,                 "lineEnd": getattr(ast_node, "end_lineno", ast_node.lineno),                 "colStart": ast_node.col_offset,                 "colEnd": getattr(ast_node, "end_col_offset", ast_node.col_offset),                 "sourceFile": self.filename,             }      # ════════════════════════════════════════════════════════════════════════     #  Expression visitors (return Node)     # ════════════════════════════════════════════════════════════════════════      def _add_node(self, node: Node) -> Node:         self.graph.add_node(node)         return node      def visit_Constant(self, n: ast.Constant) -> Node:         node = Node(             id=self._new_id("lit"), category=CATEGORY_DATA, type="literal",             label=repr(n.value), value=n.value,             inputs=[PortDef("in")], outputs=[PortDef("out")],         )         self._record_source(node.id, n)         return self._add_node(node)      def visit_Name(self, n: ast.Name) -> Node:         node = Node(             id=self._new_id("name"), category=CATEGORY_DATA, type="name",             label=n.id, value=n.id,             inputs=[PortDef("in")], outputs=[PortDef("out")],         )         self._record_source(node.id, n)         return self._add_node(node)      def visit_Attribute(self, n: ast.Attribute) -> Node:         obj = self.visit_expr(n.value)         node = Node(             id=self._new_id("attr"), category=CATEGORY_DATA, type="attribute",             label=n.attr, inputs=[PortDef("object")], outputs=[PortDef("out")],         )         self._record_source(node.id, n)         self._add_node(node)         self.graph.add_edge(obj.id, node.id, "out", "object")         return node      def visit_BinOp(self, n: ast.BinOp) -> Node:         left = self.visit_expr(n.left)         right = self.visit_expr(n.right)         op_name = _OP_MAP.get(type(n.op), type(n.op).__name__)         node = Node(             id=self._new_id("binop"), category=CATEGORY_DATA, type="binop",             label=op_name,             inputs=[PortDef("left"), PortDef("right")],             outputs=[PortDef("out")],         )         self._record_source(node.id, n)         self._add_node(node)         self.graph.add_edge(left.id, node.id, "out", "left")         self.graph.add_edge(right.id, node.id, "out", "right")         return node      def visit_UnaryOp(self, n: ast.UnaryOp) -> Node:         operand = self.visit_expr(n.operand)         op_name = _UNARY_MAP.get(type(n.op), type(n.op).__name__)         node = Node(             id=self._new_id("unaryop"), category=CATEGORY_DATA, type="unaryop",             label=op_name, inputs=[PortDef("operand")], outputs=[PortDef("out")],         )         self._record_source(node.id, n)         self._add_node(node)         self.graph.add_edge(operand.id, node.id, "out", "operand")         return node      def visit_Compare(self, n: ast.Compare) -> Node:         left = self.visit_expr(n.left)         op_name = _CMP_MAP.get(type(n.ops[0]), "?") if n.ops else "?"         node = Node(             id=self._new_id("cmp"), category=CATEGORY_DATA, type="compare",             label=op_name,             inputs=[PortDef("left"), PortDef("right")],             outputs=[PortDef("out")],         )         self._record_source(node.id, n)         self._add_node(node)         self.graph.add_edge(left.id, node.id, "out", "left")         for comp in n.comparators:             right = self.visit_expr(comp)             self.graph.add_edge(right.id, node.id, "out", "right")         return node      def visit_BoolOp(self, n: ast.BoolOp) -> Node:         """and / or — chain as nested binop-style."""         op_name = "And" if isinstance(n.op, ast.And) else "Or"         values = [self.visit_expr(v) for v in n.values]         # Left-fold: a and b and c  →  ((a and b) and c)         result = values[0]         for v in values[1:]:             node = Node(                 id=self._new_id("boolop"), category=CATEGORY_DATA, type="binop",                 label=op_name,                 inputs=[PortDef("left"), PortDef("right")],                 outputs=[PortDef("out")],             )             self._record_source(node.id, n)             self._add_node(node)             self.graph.add_edge(result.id, node.id, "out", "left")             self.graph.add_edge(v.id, node.id, "out", "right")             result = node         return result      def visit_Call(self, n: ast.Call) -> Node:         func = self.visit_expr(n.func)         # Extract label         if isinstance(n.func, ast.Name):             fn_label = n.func.id         elif isinstance(n.func, ast.Attribute):             fn_label = n.func.attr         else:             fn_label = "call"         inputs = [PortDef(f"arg_{i}") for i in range(len(n.args))]         node = Node(             id=self._new_id("call"), category=CATEGORY_ACTION, type="call",             label=fn_label, inputs=inputs, outputs=[PortDef("result")],         )         self._record_source(node.id, n)         self._add_node(node)         self.graph.add_edge(func.id, node.id, "out", "callable")         for i, arg in enumerate(n.args):             arg_node = self.visit_expr(arg)             self.graph.add_edge(arg_node.id, node.id, "out", f"arg_{i}")         return node      def visit_Subscript(self, n: ast.Subscript) -> Node:         value = self.visit_expr(n.value)         sl = self.visit_expr(n.slice) if isinstance(n.slice, ast.expr) else None         node = Node(             id=self._new_id("sub"), category=CATEGORY_DATA, type="subscr",             label="[]",             inputs=[PortDef("value"), PortDef("index")],             outputs=[PortDef("out")],         )         self._record_source(node.id, n)         self._add_node(node)         self.graph.add_edge(value.id, node.id, "out", "value")         if sl:             self.graph.add_edge(sl.id, node.id, "out", "index")         return node      def visit_List(self, n: ast.List) -> Node:         inputs = [PortDef(f"elt_{i}") for i in range(len(n.elts))]         node = Node(             id=self._new_id("list"), category=CATEGORY_DATA, type="list_literal",             label="list", inputs=inputs, outputs=[PortDef("out")],         )         self._record_source(node.id, n)         self._add_node(node)         for i, elt in enumerate(n.elts):             elt_node = self.visit_expr(elt)             self.graph.add_edge(elt_node.id, node.id, "out", f"elt_{i}")         return node      def visit_Tuple(self, n: ast.Tuple) -> Node:         inputs = [PortDef(f"elt_{i}") for i in range(len(n.elts))]         node = Node(             id=self._new_id("tup"), category=CATEGORY_DATA, type="tuple_literal",             label="tuple", inputs=inputs, outputs=[PortDef("out")],         )         self._record_source(node.id, n)         self._add_node(node)         for i, elt in enumerate(n.elts):             elt_node = self.visit_expr(elt)             self.graph.add_edge(elt_node.id, node.id, "out", f"elt_{i}")         return node      def visit_Dict(self, n: ast.Dict) -> Node:         n_pairs = len(n.keys)         inputs = [PortDef(f"key_{i}") for i in range(n_pairs)] + \                  [PortDef(f"val_{i}") for i in range(n_pairs)]         node = Node(             id=self._new_id("dict"), category=CATEGORY_DATA, type="dict_literal",             label="dict", inputs=inputs, outputs=[PortDef("out")],         )         self._record_source(node.id, n)         self._add_node(node)         for i, (k, v) in enumerate(zip(n.keys, n.values)):             if k is not None:                 k_node = self.visit_expr(k)                 self.graph.add_edge(k_node.id, node.id, "out", f"key_{i}")             v_node = self.visit_expr(v)             self.graph.add_edge(v_node.id, node.id, "out", f"val_{i}")         return node      def _fallback_expr(self, n: ast.expr) -> Node:         code = ast.get_source_segment(self.source, n) or "?"         node = _make_code_block(self._new_id("fb"), code)         self._record_source(node.id, n)         return self._add_node(node)      def visit_expr(self, n: ast.expr) -> Node:         dispatch: dict[type, Any] = {             ast.Constant: self.visit_Constant,             ast.Name: self.visit_Name,             ast.BinOp: self.visit_BinOp,             ast.UnaryOp: self.visit_UnaryOp,             ast.BoolOp: self.visit_BoolOp,             ast.Compare: self.visit_Compare,             ast.Call: self.visit_Call,             ast.Attribute: self.visit_Attribute,             ast.Subscript: self.visit_Subscript,             ast.List: self.visit_List,             ast.Tuple: self.visit_Tuple,             ast.Dict: self.visit_Dict,         }         handler = dispatch.get(type(n), self._fallback_expr)         return handler(n)      # ════════════════════════════════════════════════════════════════════════     #  Statement visitors (return node ID or None)     # ════════════════════════════════════════════════════════════════════════      def _track(self, node: Node) -> str:         self._last_stmt_id = node.id         return node.id      def visit_Expr(self, n: ast.Expr) -> str | None:         val = self.visit_expr(n.value)         return val.id if val else None      def visit_Assign(self, n: ast.Assign) -> str | None:         value = self.visit_expr(n.value)         last_id = None         for target in n.targets:             if isinstance(target, ast.Name):                 node = Node(                     id=self._new_id("assign"), category=CATEGORY_ACTION, type="assign",                     label=target.id,                     inputs=[PortDef("value")], outputs=[],                 )                 self._record_source(node.id, n)                 self.graph.add_node(node)                 self.graph.add_edge(value.id, node.id, "out", "value")                 self.graph.variables[target.id] = f"var_{self._counter}"                 last_id = self._track(node)             else:                 # Fallback for complex targets (subscript, attribute)                 code = ast.get_source_segment(self.source, n) or "?"                 fb = _make_code_block(self._new_id("fb"), code)                 self._record_source(fb.id, n)                 self.graph.add_node(fb)                 last_id = fb.id         return last_id      def visit_AugAssign(self, n: ast.AugAssign) -> str | None:         target = self.visit_expr(n.target)         value = self.visit_expr(n.value)         op_name = _OP_MAP.get(type(n.op), type(n.op).__name__)         target_name = n.target.id if isinstance(n.target, ast.Name) else "?"         node = Node(             id=self._new_id("augassign"), category=CATEGORY_ACTION, type="assign",             label=f"{target_name} {op_name}=",             inputs=[PortDef("target"), PortDef("value")], outputs=[],         )         self._record_source(node.id, n)         self.graph.add_node(node)         self.graph.add_edge(target.id, node.id, "out", "target")         self.graph.add_edge(value.id, node.id, "out", "value")         return self._track(node)      def visit_Return(self, n: ast.Return) -> str | None:         has_value = n.value is not None         inputs = [PortDef("value")] if has_value else []         node = Node(             id=self._new_id("return"), category=CATEGORY_CONTROL, type="return",             label="return", inputs=inputs, outputs=[],         )         self._record_source(node.id, n)         self.graph.add_node(node)         if has_value:             val = self.visit_expr(n.value)  # type: ignore[arg-type]             self.graph.add_edge(val.id, node.id, "out", "value")         return self._track(node)      def visit_If(self, n: ast.If, *, is_elif: bool = False) -> str | None:         test = self.visit_expr(n.test)         label = "elif" if is_elif else "if"         if_node = Node(             id=self._new_id("if"), category=CATEGORY_CONTROL, type="if",             label=label,             inputs=[PortDef("test", type="bool")],             outputs=[PortDef("body"), PortDef("orelse")],             children=[],         )         self._record_source(if_node.id, n)         self.graph.add_node(if_node)         self.graph.add_edge(test.id, if_node.id, "out", "test")          # body children         body_ids: list[str] = []         for stmt in n.body:             sid = self.visit_stmt(stmt)             if sid:                 body_ids.append(sid)         if_node.children.extend(body_ids)          # orelse: detect elif pattern (single If in orelse list)         orelse_ids: list[str] = []         if len(n.orelse) == 1 and isinstance(n.orelse[0], ast.If):             # elif chain             elif_id = self.visit_If(n.orelse[0], is_elif=True)             if elif_id:                 orelse_ids.append(elif_id)         else:             for stmt in n.orelse:                 sid = self.visit_stmt(stmt)                 if sid:                     orelse_ids.append(sid)         if_node.children.extend(orelse_ids)          # Store body/orelse boundary in edge labels for codegen         for cid in body_ids:             self.graph.add_edge(if_node.id, cid, "body", "in", label="body")         for cid in orelse_ids:             self.graph.add_edge(if_node.id, cid, "orelse", "in", label="orelse")          return self._track(if_node)      def visit_For(self, n: ast.For) -> str | None:         target = self.visit_expr(n.target)         iter_val = self.visit_expr(n.iter)         for_node = Node(             id=self._new_id("for"), category=CATEGORY_CONTROL, type="for",             label="for",             inputs=[PortDef("target"), PortDef("iter", type="iterable")],             children=[], outputs=[],         )         self._record_source(for_node.id, n)         self.graph.add_node(for_node)         self.graph.add_edge(target.id, for_node.id, "out", "target")         self.graph.add_edge(iter_val.id, for_node.id, "out", "iter")         for stmt in n.body:             sid = self.visit_stmt(stmt)             if sid:                 for_node.children.append(sid)                 self.graph.add_edge(for_node.id, sid, "body", "in", label="body")         return self._track(for_node)      def visit_While(self, n: ast.While) -> str | None:         test = self.visit_expr(n.test)         while_node = Node(             id=self._new_id("while"), category=CATEGORY_CONTROL, type="while",             label="while",             inputs=[PortDef("test", type="bool")],             children=[], outputs=[],         )         self._record_source(while_node.id, n)         self.graph.add_node(while_node)         self.graph.add_edge(test.id, while_node.id, "out", "test")         for stmt in n.body:             sid = self.visit_stmt(stmt)             if sid:                 while_node.children.append(sid)                 self.graph.add_edge(while_node.id, sid, "body", "in", label="body")         return self._track(while_node)      def visit_Break(self, n: ast.Break) -> str | None:         node = Node(             id=self._new_id("break"), category=CATEGORY_CONTROL, type="break",             label="break", inputs=[], outputs=[],         )         self._record_source(node.id, n)         self.graph.add_node(node)         return self._track(node)      def visit_Continue(self, n: ast.Continue) -> str | None:         node = Node(             id=self._new_id("cont"), category=CATEGORY_CONTROL, type="continue",             label="continue", inputs=[], outputs=[],         )         self._record_source(node.id, n)         self.graph.add_node(node)         return self._track(node)      def visit_FunctionDef(self, n: ast.FunctionDef) -> str | None:         # Store real argument names in PortDef         arg_ports = [PortDef(name=a.arg, type="any") for a in n.args.args]         fn_node = Node(             id=self._new_id("fn"), category=CATEGORY_STRUCTURE, type="function_def",             label=n.name,             inputs=arg_ports, children=[],             outputs=[PortDef("result")],         )         self._record_source(fn_node.id, n)         self.graph.add_node(fn_node)         for stmt in n.body:             sid = self.visit_stmt(stmt)             if sid:                 fn_node.children.append(sid)                 self.graph.add_edge(fn_node.id, sid, "body", "in", label="body")         return self._track(fn_node)      def visit_ClassDef(self, n: ast.ClassDef) -> str | None:         cls_node = Node(             id=self._new_id("cls"), category=CATEGORY_STRUCTURE, type="class_def",             label=n.name,             inputs=[], children=[], outputs=[],         )         self._record_source(cls_node.id, n)         self.graph.add_node(cls_node)         for stmt in n.body:             sid = self.visit_stmt(stmt)             if sid:                 cls_node.children.append(sid)                 self.graph.add_edge(cls_node.id, sid, "body", "in", label="body")         return self._track(cls_node)      def visit_Import(self, n: ast.Import) -> str | None:         last_id = None         for alias in n.names:             node = Node(                 id=self._new_id("import"), category=CATEGORY_ACTION, type="import",                 label=alias.name, value=alias.asname,                 inputs=[], outputs=[],             )             self.graph.add_node(node)             last_id = self._track(node)         return last_id      def visit_ImportFrom(self, n: ast.ImportFrom) -> str | None:         node = Node(             id=self._new_id("import"), category=CATEGORY_ACTION, type="import_from",             label=n.module or ".", value=[a.name for a in n.names],             inputs=[], outputs=[],         )         self.graph.add_node(node)         return self._track(node)      def _fallback_stmt(self, n: ast.stmt) -> str | None:         code = ast.get_source_segment(self.source, n) or "?"         node = _make_code_block(self._new_id("fb"), code)         self._record_source(node.id, n)         self.graph.add_node(node)         return node.id      def visit_stmt(self, n: ast.stmt) -> str | None:         dispatch: dict[type, Any] = {             ast.Expr: self.visit_Expr,             ast.Assign: self.visit_Assign,             ast.AugAssign: self.visit_AugAssign,             ast.Return: self.visit_Return,             ast.If: self.visit_If,             ast.For: self.visit_For,             ast.While: self.visit_While,             ast.Break: self.visit_Break,             ast.Continue: self.visit_Continue,             ast.FunctionDef: self.visit_FunctionDef,             ast.ClassDef: self.visit_ClassDef,             ast.Import: self.visit_Import,             ast.ImportFrom: self.visit_ImportFrom,             ast.Pass: lambda _n: None,         }         handler = dispatch.get(type(n), self._fallback_stmt)         return handler(n)      # ════════════════════════════════════════════════════════════════════════     #  Main entry     # ════════════════════════════════════════════════════════════════════════      def parse(self) -> dict:         """Parse source and return a full graph-ai.json dict."""         try:             tree = ast.parse(self.source, filename=self.filename)         except SyntaxError:             raise         for stmt in tree.body:             self.visit_stmt(stmt)         raw = self.graph.to_dict()         full = build_ir(raw)         full["sourceMap"] = self.source_map         full["metadata"]["generatedAt"] = "__NOW__"         return full   # ── Public API ────────────────────────────────────────────────────────────   def parse_source(source: str, filename: str = "<unknown>") -> dict:     """Parse Python source string → graph-ai.json dict."""     return PythonParser(source, filename).parse()   def parse_file(path: str) -> dict:     """Parse a Python file from disk → graph-ai.json dict."""     p = Path(path)     return PythonParser(p.read_text(encoding="utf-8"), str(p)).parse()